body:
verilator version : 5.012

I created a SV design to do a bitwise AND between 3 separated inputs of 8-bits and another bitwise AND between 3 inputs, 2 of them are packed in an array as illustrated bellow. Then, I created a SV testbench to test this module with randomized inputs in every iteration.  The results at the end show that the inputs packed in the array are blocked after the first iteration unlike the other inputs and the fact that the out_1 changes when C changes mean that design is simulated only the array inputs are blocked. Is it that verilator can't handle array inputs or am I missing something like an option that I should use. Thank in advance for you help.

```
//design

module And 

            ( output wire [7:0] out_0,
             output wire [7:0] out_1,
        	 input wire [7:0] In [1:0],
             input wire [7:0] In0,
             input wire [7:0] In1,
             input wire [7:0] C);
    assign out_1 = In[0] & In[1] & C ;
    assign out_0 = In0 & In1 & C ;
    always @ (In[0], In[1], In0, In1) begin
        $display("design_level : in_array = {%b, %b, %b} | in_sing = {%b, %b, %b}", In[0], In[1], C, In0, In1, C);
    end

endmodule


// Testbench

`include "And.sv"
module Test ;

          //cell's parameters and variables 
    parameter w=8 ; //w=width of data
    parameter stimu_num = 20; //number of stimulus
    //inputs
    reg [w-1:0] In0;//an array of N inputs with w width
    reg [w-1:0] In1;//an array of N inputs with w width
    reg [w-1:0] In [1:0];//an array of N inputs with w width
    reg [7:0] C = 8'b00000000;
    int i = 0;
    //outputs
    wire [w-1:0] out_0;
    wire [w-1:0] out_1;
    int tmp_rand;
      //instances
    And and_inst_0 (.out_0(out_0), .out_1(out_1), .In(In), .In0(In0), .In1(In1), .C(C) );
    //And and_inst_1 ( .out(out_1), .In(In));
      initial begin
        repeat (stimu_num) begin
            $display("iteration %0d", i);
            C =~C;
            tmp_rand = $urandom_range(0, (2**w)-1); 
            In0 = tmp_rand[7:0];
            tmp_rand= $urandom_range(0, (2**w)-1); 
            In1 = tmp_rand[7:0];
            In ={In1, In0};
            #5; //signal propagation delay 
                //check and operator first instance with no array
            $display("Test ");
            if (out_0 !== (In0 & In1 & C))
                $display("AND gate test failed for In0=%b, In1=%b and result is out_sing=%b", In0, In1, out_0);//
            else 
                $display("AND gate test passed for In0=%b, In1=%b and result is out_sing=%b", In0, In1, out_0);
            //chack and operator second instance with ana array 
            if (out_1 !== (In[0] & In[1] & C))
                $display("AND gate test failed for In0=%b, In1=%b and result is out_arr=%b", In[0], In[1], out_1);
            else 
               $display("AND gate test passed for In0=%b, In1=%b and result is out_arr=%b", In[0], In[1], out_1);
            i++;
            end
        $finish;
      end
endmodule
```

